ValidationRule.errorConditionFormula:
or( and( $User.Department = 'DAAS (DAAS)', RecordType.DeveloperName = 'Technical_Solutions', not( ISNULL( Approved_by_Finance__c )), Not(ischanged( Status__c ))),
and ( $User.Department <> 'DAAS (DAAS)', $Profile.Name <> 'SW Billing', $Profile.Name <> 'SW SalesOps', $Profile.Name <> 'SW SalesOps Extended', $Profile.Name <> "SW CSM Internal", RecordType.DeveloperName = 'Technical_Solutions', not( ISNULL( Approved_by_Finance__c )) )
)
